output-schema.schema:
{
  "directive_id": "string (UUID)",
  "created_at": "ISO 8601 timestamp",
  "raw_input": "string (original user input)",

  "priorities": {
    "categories": [
      {
        "name": "string (category name)",
        "name_lt": "string (Lithuanian variant)",
        "weight_modifier": "number (0.5-2.0, default 1.0)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "confidence": "number (0.0-1.0)"
      }
    ],
    "attributes": [
      {
        "attribute": "string (e.g., 'premium', 'eco-friendly')",
        "attribute_lt": "string (Lithuanian variant)",
        "boost_factor": "number (1.1-2.0)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "confidence": "number (0.0-1.0)"
      }
    ],
    "brands": [
      {
        "brand": "string (brand name)",
        "action": "PROMOTE | NEUTRAL",
        "weight_modifier": "number (1.0-2.0)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "confidence": "number (0.0-1.0)"
      }
    ]
  },

  "suppressions": {
    "attributes": [
      {
        "attribute": "string",
        "attribute_lt": "string (Lithuanian variant)",
        "suppress_factor": "number (0.1-0.9)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "reason": "string (why suppressed)",
        "confidence": "number (0.0-1.0)"
      }
    ],
    "brands": [
      {
        "brand": "string (competitor brand)",
        "action": "EXCLUDE | DEMOTE",
        "suppress_factor": "number (0.0-0.5)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "reason": "string (e.g., 'competitor', 'discontinued')",
        "confidence": "number (0.0-1.0)"
      }
    ],
    "categories": [
      {
        "name": "string",
        "name_lt": "string",
        "suppress_factor": "number (0.1-0.9)",
        "scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
        "valid_until": "ISO 8601 date or null",
        "reason": "string",
        "confidence": "number (0.0-1.0)"
      }
    ]
  },

  "volume_preference": {
    "strategy": "HIGH_VOLUME | LONG_TAIL | BALANCED | MIXED",
    "high_volume_threshold": "number (monthly searches)",
    "long_tail_max_words": "number (typically 4-7)",
    "rationale": "string (why this strategy)",
    "confidence": "number (0.0-1.0)"
  },

  "temporal_context": {
    "detection_signals": ["string (phrases that indicated temporality)"],
    "primary_scope": "PERMANENT | QUARTERLY | SEASONAL | CAMPAIGN",
    "quarter": "Q1 | Q2 | Q3 | Q4 | null",
    "season": "SPRING | SUMMER | AUTUMN | WINTER | null",
    "campaign_name": "string or null",
    "effective_date": "ISO 8601 date",
    "expiry_date": "ISO 8601 date or null"
  },

  "contradictions": [
    {
      "conflict": "string (description of contradiction)",
      "items": ["string (conflicting items)"],
      "resolution_suggestion": "string (how to resolve)"
    }
  ],

  "ambiguities": [
    {
      "statement": "string (ambiguous input segment)",
      "possible_interpretations": ["string"],
      "chosen_interpretation": "string or null",
      "needs_clarification": "boolean"
    }
  ],

  "lithuanian_variants": {
    "generated": [
      {
        "original": "string",
        "variants": ["string (Lithuanian translations/variants)"],
        "includes_misspellings": "boolean"
      }
    ]
  },

  "metadata": {
    "parser_version": "1.0.0",
    "total_priorities_extracted": "number",
    "total_suppressions_extracted": "number",
    "average_confidence": "number",
    "requires_human_review": "boolean",
    "review_reasons": ["string"]
  }
}

